#include <iostream>
#include <thread>

void task() {
    std::cout << "Thread processing" << std::endl;
}

int main() {
    std::thread t(task);
    t.join();
    return 0;
}

examples.toCode:
package main

import (
	"fmt"
	"sync"
)

func task(wg *sync.WaitGroup) {
	defer wg.Done()
	fmt.Println("Goroutine processing")
}

func main() {
	var wg sync.WaitGroup
	wg.Add(1)
	go task(&wg)
	wg.Wait()
}

